class Solution {
public:
    int eatenApples(vector<int>& apples, vector<int>& days) {
        using pii = pair<int, int>;
        priority_queue<pii, vector<pii>, greater<pii>> q;
        int n = days.size();
        int ans = 0, i = 0;
        while (i < n || !q.empty()) {
            if (i < n && apples[i]) {
                q.emplace(i + days[i] - 1, apples[i]);
            }
            while (!q.empty() && q.top().first < i) {
                q.pop();
            }
            if (!q.empty()) {
                auto [t, v] = q.top();
                q.pop();
                --v;
                ++ans;
                if (v && t > i) {
                    q.emplace(t, v);
                }
            }
            ++i;
        }
        return ans;
    }
};
